const body = $input.first().json.body || $input.first().json;
const errors = [];

if (!body || typeof body !== 'object') {
  errors.push('Request body is required');
}

const rawIdea = body?.rawIdea?.toString().trim() || '';
const url = body?.url?.toString().trim() || '';

if (!rawIdea && !url) {
  errors.push('Either rawIdea or url must be provided');
}

if (url && !/^https?:\/\/.+\..+/.test(url)) {
  errors.push('url must be a valid HTTP/HTTPS URL');
}

if (rawIdea && rawIdea.length > 10000) {
  errors.push('rawIdea must be under 10,000 characters');
}

const payloadSize = JSON.stringify(body).length;
if (payloadSize > 1048576) {
  errors.push('Payload exceeds 1MB size limit');
}

// Sanitize inputs
const sanitized = {
  rawIdea: rawIdea.replace(/<[^>]*>/g, '').substring(0, 10000),
  url: url,
  publishImmediately: body?.publishImmediately === true,
};

if (errors.length > 0) {
  return [{json: {error: true, statusCode: 400, message: errors.join('; ')}}];
}

return [{json: {error: false, ...sanitized}}];

const input = $input.first().json;
const content = input.rawIdea || input.url;

// Simple hash function
let hash = 0;
for (let i = 0; i < content.length; i++) {
  const char = content.charCodeAt(i);
  hash = ((hash << 5) - hash) + char;
  hash = hash & hash;
}
const contentHash = Math.abs(hash).toString(36);

const submissionId = 'sub_' + Date.now().toString(36) + '_' + Math.random().toString(36).substring(2, 8);
const tenMinAgo = new Date(Date.now() - 10 * 60 * 1000).toISOString();

return [{json: {
  ...input,
  submissionId,
  contentHash,
  tenMinAgo,
  createdAt: new Date().toISOString()
}}];

const response = $input.first().json;
let text = '';

if (typeof response === 'string') {
  text = response;
} else if (response.data) {
  text = typeof response.data === 'string' ? response.data : JSON.stringify(response.data);
} else {
  text = JSON.stringify(response);
}

// Strip HTML tags
text = text.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
text = text.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
text = text.replace(/<[^>]+>/g, ' ');
text = text.replace(/&nbsp;/g, ' ');
text = text.replace(/&amp;/g, '&');
text = text.replace(/&lt;/g, '<');
text = text.replace(/&gt;/g, '>');
text = text.replace(/\s+/g, ' ').trim();

// Truncate to 5000 chars
text = text.substring(0, 5000);

if (text.length < 50) {
  return [{json: {error: true, statusCode: 422, message: 'Could not extract meaningful content from URL. Try submitting a raw idea instead.'}}];
}

const prev = $('Generate Submission ID & Dedup Hash').first().json;
return [{json: {
  ...prev,
  contentBase: text,
  inputType: 'url'
}}];

const prev = $('Generate Submission ID & Dedup Hash').first().json;
return [{json: {
  ...prev,
  contentBase: prev.rawIdea,
  inputType: 'raw_idea'
}}];

const input = $input.first().json;
return [{json: {
  submissionId: input.submissionId,
  contentHash: input.contentHash,
  contentBase: input.contentBase,
  inputType: input.inputType,
  rawIdea: input.rawIdea,
  url: input.url,
  publishImmediately: input.publishImmediately,
  createdAt: input.createdAt
}}];

