const response = $input.first().json;
let content = '';

try {
  if (response.choices && response.choices[0]) {
    content = response.choices[0].message.content;
  }
} catch(e) {
  content = '';
}

if (!content || content.trim().length === 0) {
  return [{json: {error: true, message: 'AI returned empty draft'}}];
}

// Strip meta-commentary
content = content.replace(/^(Here's|Here is|Below is|I've written|Sure,).*?\n+/i, '');
content = content.trim();

const wordCount = content.split(/\s+/).length;
if (wordCount < 300) {
  return [{json: {error: true, message: `Draft too short: ${wordCount} words (minimum 300)`}}];
}

// Extract title (first line that starts with # or is the first non-empty line)
let title = '';
const lines = content.split('\n');
for (const line of lines) {
  const trimmed = line.trim();
  if (trimmed) {
    title = trimmed.replace(/^#+\s*/, '');
    break;
  }
}

return [{json: {
  draftContent: content,
  draftTitle: title,
  wordCount,
  validated: true
}}];

